from flask import Flask, request, jsonify
import os
import re
import uuid
import tempfile
import subprocess
import threading
import time
from urllib.parse import urlparse
import boto3
import botocore
import requests

app = Flask(__name__)

AWS_REGION = os.getenv("AWS_REGION", "us-east-1")
S3_BUCKET = os.getenv("S3_BUCKET", "")
S3_PREFIX = os.getenv("S3_PREFIX", "thumbnails")
SCREENSHOT_TOOL = os.getenv("SCREENSHOT_TOOL", "chrome").lower()  # chrome or phantomjs
CHROME_BIN = os.getenv("CHROME_BIN", "/usr/bin/google-chrome")
PHANTOMJS_BIN = os.getenv("PHANTOMJS_BIN", "/usr/bin/phantomjs")
CHROME_DRIVER_BIN = os.getenv("CHROME_DRIVER_BIN", "/usr/bin/chromedriver")
PUBLIC_BASE_URL = os.getenv("PUBLIC_BASE_URL", "")
REQUEST_TIMEOUT = int(os.getenv("REQUEST_TIMEOUT", "20"))
SHOT_WIDTH = int(os.getenv("SHOT_WIDTH", "1280"))
SHOT_HEIGHT = int(os.getenv("SHOT_HEIGHT", "720"))
THUMB_WIDTH = int(os.getenv("THUMB_WIDTH", "320"))
THUMB_HEIGHT = int(os.getenv("THUMB_HEIGHT", "180"))
USE_IMAGEMAGICK = os.getenv("USE_IMAGEMAGICK", "0") == "1"

s3 = boto3.client("s3", region_name=AWS_REGION)

URL_RE = re.compile(r"^https?://", re.IGNORECASE)
PRIVATE_NETS = [
    ("10.",),
    ("127.",),
    ("169.254.",),
    ("192.168.",),
    ("172.16.",),
    ("172.17.",),
    ("172.18.",),
    ("172.19.",),
    ("172.20.",),
    ("172.21.",),
    ("172.22.",),
    ("172.23.",),
    ("172.24.",),
    ("172.25.",),
    ("172.26.",),
    ("172.27.",),
    ("172.28.",),
    ("172.29.",),
    ("172.30.",),
    ("172.31.",),
]


def is_private_host(hostname: str) -> bool:
    if not hostname:
        return True
    hostname = hostname.strip().lower()
    if hostname in ("localhost",):
        return True
    if hostname.endswith(".local"):
        return True
    if re.match(r"^\d+\.\d+\.\d+\.\d+$", hostname):
        for prefixes in PRIVATE_NETS:
            if hostname.startswith(prefixes):
                return True
    return False


def validate_url(url: str) -> bool:
    if not url or not URL_RE.match(url):
        return False
    parsed = urlparse(url)
    if parsed.scheme not in ("http", "https"):
        return False
    if not parsed.netloc:
        return False
    host = parsed.hostname or ""
    if is_private_host(host):
        return False
    return True


def s3_key_for_url(url: str) -> str:
    safe = uuid.uuid5(uuid.NAMESPACE_URL, url).hex
    return f"{S3_PREFIX}/{safe}.png"


def public_url_for_key(key: str) -> str:
    if PUBLIC_BASE_URL:
        return f"{PUBLIC_BASE_URL.rstrip('/')}/{key.lstrip('/')}"
    return f"https://{S3_BUCKET}.s3.{AWS_REGION}.amazonaws.com/{key}"


def upload_to_s3(local_path: str, key: str, content_type: str = "image/png") -> str:
    extra = {
        "ContentType": content_type,
        "CacheControl": "public, max-age=31536000, immutable",
    }
    s3.upload_file(local_path, S3_BUCKET, key, ExtraArgs=extra)
    return public_url_for_key(key)


def ensure_bucket():
    if not S3_BUCKET:
        raise RuntimeError("S3_BUCKET is required")


def capture_with_chrome(url: str, output_path: str):
    with tempfile.TemporaryDirectory() as profile_dir:
        cmd = [
            CHROME_BIN,
            "--headless",
            "--disable-gpu",
            "--no-sandbox",
            "--hide-scrollbars",
            f"--window-size={SHOT_WIDTH},{SHOT_HEIGHT}",
            f"--user-data-dir={profile_dir}",
            "--default-background-color=ffffffff",
            f"--screenshot={output_path}",
            url,
        ]
        subprocess.run(cmd, check=True, timeout=REQUEST_TIMEOUT)


def capture_with_phantomjs(url: str, output_path: str):
    script = """
var page = require('webpage').create();
page.viewportSize = { width: %d, height: %d };
page.clipRect = { top: 0, left: 0, width: %d, height: %d };
page.onResourceError = function(resourceError) {};
page.onError = function(msg, trace) {};
page.open('%s', function(status) {
    if (status !== 'success') {
        phantom.exit(1);
    } else {
        window.setTimeout(function() {
            page.render('%s');
            phantom.exit();
        }, 2000);
    }
});
""" % (
        SHOT_WIDTH,
        SHOT_HEIGHT,
        SHOT_WIDTH,
        SHOT_HEIGHT,
        url.replace("'", "\\'"),
        output_path.replace("'", "\\'"),
    )
    with tempfile.NamedTemporaryFile(suffix=".js", delete=False) as f:
        f.write(script.encode("utf-8"))
        script_path = f.name
    try:
        subprocess.run([PHANTOMJS_BIN, script_path], check=True, timeout=REQUEST_TIMEOUT)
    finally:
        try:
            os.unlink(script_path)
        except OSError:
            pass


def resize_thumbnail(src_path: str, dst_path: str):
    if USE_IMAGEMAGICK:
        subprocess.run(
            [
                "convert",
                src_path,
                "-thumbnail",
                f"{THUMB_WIDTH}x{THUMB_HEIGHT}^",
                "-gravity",
                "north",
                "-extent",
                f"{THUMB_WIDTH}x{THUMB_HEIGHT}",
                dst_path,
            ],
            check=True,
            timeout=REQUEST_TIMEOUT,
        )
    else:
        from PIL import Image, ImageOps

        with Image.open(src_path) as img:
            img = img.convert("RGB")
            thumb = ImageOps.fit(img, (THUMB_WIDTH, THUMB_HEIGHT), method=Image.Resampling.LANCZOS)
            thumb.save(dst_path, format="PNG")


def generate_screenshot(url: str) -> str:
    ensure_bucket()
    key = s3_key_for_url(url)
    with tempfile.TemporaryDirectory() as td:
        full_path = os.path.join(td, "full.png")
        thumb_path = os.path.join(td, "thumb.png")
        if SCREENSHOT_TOOL == "phantomjs":
            capture_with_phantomjs(url, full_path)
        else:
            capture_with_chrome(url, full_path)
        resize_thumbnail(full_path, thumb_path)
        return upload_to_s3(thumb_path, key)


@app.route("/health", methods=["GET"])
def health():
    return jsonify({"status": "ok"}), 200


@app.route("/screenshot", methods=["POST"])
def screenshot():
    data = request.get_json(silent=True) or request.form or {}
    url = (data.get("url") or "").strip()
    if not validate_url(url):
        return jsonify({"error": "invalid_url"}), 400

    try:
        screenshot_url = generate_screenshot(url)
        return jsonify({"url": url, "screenshot_url": screenshot_url}), 200
    except botocore.exceptions.BotoCoreError as e:
        return jsonify({"error": "s3_error", "detail": str(e)}), 500
    except subprocess.TimeoutExpired:
        return jsonify({"error": "timeout"}), 504
    except subprocess.CalledProcessError as e:
        return jsonify({"error": "capture_failed", "detail": str(e)}), 500
    except Exception as e:
        return jsonify({"error": "internal_error", "detail": str(e)}), 500


@app.route("/screenshot/async", methods=["POST"])
def screenshot_async():
    data = request.get_json(silent=True) or request.form or {}
    url = (data.get("url") or "").strip()
    if not validate_url(url):
        return jsonify({"error": "invalid_url"}), 400

    job_id = uuid.uuid4().hex
    result = {"status": "pending", "url": url, "job_id": job_id}
    path = os.path.join(tempfile.gettempdir(), f"screenshot_{job_id}.json")

    def worker():
        try:
            screenshot_url = generate_screenshot(url)
            payload = {"status": "done", "url": url, "job_id": job_id, "screenshot_url": screenshot_url}
        except Exception as e:
            payload = {"status": "error", "url": url, "job_id": job_id, "error": str(e)}
        with open(path, "w") as f:
            f.write(jsonify(payload).get_data(as_text=True))

    threading.Thread(target=worker, daemon=True).start()
    return jsonify(result), 202


@app.route("/screenshot/<job_id>", methods=["GET"])
def screenshot_status(job_id):
    path = os.path.join(tempfile.gettempdir(), f"screenshot_{job_id}.json")
    if not os.path.exists(path):
        return jsonify({"error": "not_found"}), 404
    try:
        with open(path, "r") as f:
            content = f.read()
        return app.response_class(content, mimetype="application/json"), 200
    except Exception as e:
        return jsonify({"error": "internal_error", "detail": str(e)}), 500


if __name__ == "__main__":
    ensure_bucket()
    app.run(host="0.0.0.0", port=int(os.getenv("PORT", "8080")))